from pieces import Piece

class Board:
    def __init__(self):
        self._setup_board()

    def _setup_board(self):
        # Initialize an 8x8 grid with alternating dark and light squares
        self.board = []
        for i in range(8):
            row = []
            for j in range(8):
                if (i + j) % 2 == 0:
                    if i < 3:
                        row.append(Piece('B'))  # Black pieces on top
                    elif i > 4:
                        row.append(Piece('W'))  # White pieces on bottom
                    else:
                        row.append(None)
                else:
                    row.append(None)
            self.board.append(row)

    def print_board(self):
        for row in self.board:
            print(" ".join([p.color if p else None for p in row]))

    def move_piece(self, from_pos, to_pos):
        # Validate positions
        if not (0 <= from_pos[0] < 8 and 0 <= from_pos[1] < 8 and 0 <= to_pos[0] < 8 and 0 <= to_pos[1] < 8):
            raise ValueError("Invalid position")

        from_piece = self.board[from_pos[0]][from_pos[1]]
        to_square = self.board[to_pos[0]][to_pos[1]]

        if not from_piece:
            raise ValueError("No piece at from position")
        if to_square:
            raise ValueError("Piece already exists at to position")

        # Move the piece
        self.board[from_pos[0]][from_pos[1]] = None
        self.board[to_pos[0]][to_pos[1]] = from_piece

        # Check for capturing and promotion
        intermediate_position = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
        captured_piece = self.board[intermediate_position[0]][intermediate_position[1]]
        if captured_piece:
            self.board[intermediate_position[0]][intermediate_position[1]] = None
        if to_pos[0] == 0 and from_piece.color == 'B' or to_pos[0] == 7 and from_piece.color == 'W':
            from_piece.promote_to_king()

    def find_captures(self, piece_color):
        captures = []
        for row in range(8):
            for col in range(8):
                if self.board[row][col] and self.board[row][col].color == piece_color:
                    captures.extend(self._find_captures_from_position(row, col))
        return captures

    def _find_captures_from_position(self, row, col):
        captures = []
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for dr, dc in directions:
            intermediate_row, intermediate_col = row + dr, col + dc
            if not (0 <= intermediate_row < 8 and 0 <= intermediate_col < 8):
                continue

            next_row, next_col = intermediate_row + dr, intermediate_col + dc
            if not (0 <= next_row < 8 and 0 <= next_col < 8):
                continue

            if self.board[intermediate_row][intermediate_col] is None and self.board[next_row][next_col]:
                captures.append(((row, col), (next_row, next_col)))
        return captures

    def check_for_winner(self):
        black_pieces = sum(1 for row in range(8) for col in range(8) if self.board[row][col] and self.board[row][col].color == 'B')
        white_pieces = sum(1 for row in range(8) for col in range(8) if self.board[row][col] and self.board[row][col].color == 'W')

        if black_pieces == 0:
            return 'White wins!'
        elif white_pieces == 0:
            return 'Black wins!'
        else:
            return None

