        to_pos = (ord(move[3].lower()) - ord('a'), int(move[4]) - 1)
        try:
            board.move_piece(from_pos, to_pos)
            board.print_board()
        except ValueError as e:
            print(e)

    winner = board.check_for_winner()
    if winner:
        print(winner)
